 1→import { graphql } from "relay-runtime";
 2→import { Match, Show, Switch } from "solid-js";
 3→import { createFragment } from "solid-relay";
 4→import { PostCard_post$key } from "./__generated__/PostCard_post.graphql.ts";
 5→import { ArticleCard } from "./ArticleCard.tsx";
 6→import { NoteCard } from "./NoteCard.tsx";
 7→
 8→export interface PostCardProps {
 9→  $post: PostCard_post$key;
10→}
11→
12→export function PostCard(props: PostCardProps) {
13→  const post = createFragment(
14→    graphql`
15→      fragment PostCard_post on Post
16→        @argumentDefinitions(
17→          locale: { type: "Locale" },
18→        )
19→      {
20→        __typename
21→        ...NoteCard_note
22→        ...ArticleCard_article @arguments(locale: $locale)
23→      }
24→    `,
25→    () => props.$post,
26→  );
27→
28→  return (
29→    <Show when={post()}>
30→      {(post) => (
31→        <Switch>
32→          <Match when={post().__typename === "Note"}>
33→            <NoteCard $note={post()} />
34→          </Match>
35→          <Match when={post().__typename === "Article"}>
36→            <ArticleCard $article={post()} />
37→          </Match>
38→        </Switch>
39→      )}
40→    </Show>
41→  );
42→}
