159→interface Env {
160→  docId?: string | null;
161→  title: string;
162→  localDomain: string;
163→  origin: string;
164→  mentionedActors: Record<string, Actor>;
165→  hashtags: string[];
166→  macros: Record<string, unknown>;
167→}
