169→export interface RenderMarkupOptions {
170→  kv?: Keyv | null;
171→  docId?: string | null;
172→  refresh?: boolean;
173→}
174→
175→export async function renderMarkup(
176→  fedCtx: Context<ContextData> | null | undefined,
177→  markup: string,
178→  options: RenderMarkupOptions = {},
179→): Promise<RenderedMarkup> {
180→  let cacheKey: string | undefined;
181→  if (options.kv != null) {
182→    const digest = await crypto.subtle.digest(
183→      "SHA-256",
184→      new TextEncoder().encode(
185→        `${JSON.stringify(options.docId ?? null)}\n${markup}`,
186→      ),
187→    );
188→    cacheKey = `${KV_NAMESPACE}/${KV_CACHE_VERSION}/markup/${
189→      encodeAscii85(digest)
190→    }`;
191→    if (!options.refresh) {
192→      const cached = await options.kv.get<RenderedMarkup>(cacheKey);
193→      if (cached != null) return cached;
194→    }
195→  }
196→  const localDomain = fedCtx == null
197→    ? "hackers.pub"
198→    : new URL(fedCtx.canonicalOrigin).host;
199→  const tmpMd = MarkdownItAsync().use(mention, {
200→    localDomain() {
201→      return localDomain;
202→    },
203→  });
204→  const tmpEnv: { mentions: string[] } = { mentions: [] };
205→  await tmpMd.renderAsync(markup, tmpEnv);
206→  const mentions = new Set(tmpEnv.mentions);
207→  logger.trace("Mentions: {mentions}", { mentions });
208→  const mentionedActors = fedCtx == null
209→    ? {}
210→    : await persistActorsByHandles(fedCtx, [...mentions]);
211→  logger.trace("Mentioned actors: {mentionedActors}", { mentionedActors });
212→  const env: Env = {
213→    docId: options.docId,
214→    title: "",
215→    localDomain,
216→    origin: fedCtx == null ? "https://hackers.pub" : fedCtx.canonicalOrigin,
217→    mentionedActors,
218→    hashtags: [],
219→    macros: {},
220→  };
221→  const rawHtml = (await md.renderAsync(markup, env))
222→    .replaceAll('<?xml version="1.0" encoding="UTF-8" standalone="no"?>', "")
223→    .replaceAll(
224→      '<!DOCTYPE svg PUBLIC "-//W3C//DTD SVG 1.1//EN"\n' +
225→        ' "http://www.w3.org/Graphics/SVG/1.1/DTD/svg11.dtd">',
226→      "",
227→    );
228→  const html = sanitizeHtml(rawHtml);
229→  const excerptHtml = sanitizeExcerptHtml(rawHtml);
230→  const text = stripHtml(rawHtml);
231→  const toc = toToc(tocTree, options.docId);
232→  const rendered: RenderedMarkup = {
233→    html,
234→    excerptHtml,
235→    text,
236→    title: env.title,
237→    toc: toc.level < 1 ? toc.children : [toc],
238→    mentions: mentionedActors,
239→    hashtags: env.hashtags ?? [],
240→  };
241→  if (options.kv != null && cacheKey != null) {
242→    await options.kv.set(cacheKey, rendered);
243→  }
244→  return rendered;
245→}
