252→interface InternalToc {
253→  l: 0 | 1 | 2 | 3 | 4 | 5 | 6;
254→  n: string;
255→  c: InternalToc[];
256→}
257→
258→export interface Toc {
259→  id: string;
260→  level: 0 | 1 | 2 | 3 | 4 | 5 | 6;
261→  title: string;
262→  children: Toc[];
263→}
264→
265→function toToc(toc: InternalToc, docId?: string | null): Toc {
266→  return {
267→    id: slugifyTitle(toc.n.trimStart(), docId),
268→    level: toc.l,
269→    title: toc.n.trimStart(),
270→    children: toc.c.map((t) => toToc(t, docId)),
271→  };
272→}
