280→export async function extractMentionsFromHtml(
281→  fedCtx: Context<ContextData>,
282→  html: string,
283→  options: ExtractMentionsFromHtmlOptions = {},
284→): Promise<{ actor: Actor }[]> {
285→  let cacheKey: string | undefined;
286→  if (options.kv != null) {
287→    const digest = await crypto.subtle.digest(
288→      "SHA-256",
289→      new TextEncoder().encode(html),
290→    );
291→    cacheKey = `${KV_NAMESPACE}/${KV_CACHE_VERSION}/mentions/${
292→      encodeAscii85(digest)
293→    }`;
294→    const cached = await options.kv.get<Actor[]>(cacheKey);
295→    if (cached) return cached.map((actor) => ({ actor }));
296→  }
297→  const $ = load(html, null, false);
298→  const mentionHrefs = new Set<string>();
299→  $("a.mention[href]:not(.hashtag)").each((_, el) => {
300→    const href = $(el).attr("href");
301→    if (href != null) mentionHrefs.add(href);
302→  });
303→  if (mentionHrefs.size < 1) return [];
304→  const { db } = fedCtx.data;
305→  const actors = await db.query.actorTable.findMany({
306→    where: {
307→      OR: [
308→        { iri: { in: [...mentionHrefs] } },
309→        { url: { in: [...mentionHrefs] } },
310→        { RAW: (table) => arrayOverlaps(table.aliases, [...mentionHrefs]) },
311→      ],
312→    },
313→  });
314→  for (const actor of actors) {
315→    mentionHrefs.delete(actor.iri);
316→    if (actor.url != null) mentionHrefs.delete(actor.url);
317→    for (const alias of actor.aliases) mentionHrefs.delete(alias);
318→  }
319→  if (mentionHrefs.size < 1) return actors.map((actor) => ({ actor }));
320→  const mentionedUrls = [...mentionHrefs];
321→  logger.debug(
322→    "There are mentions to actors that are not persisted: {mentionedUrls}",
323→    { mentionedUrls },
324→  );
325→  const promises = mentionedUrls.map(async (href) => {
326→    try {
327→      return [
328→        href,
329→        await deadline(fedCtx.lookupObject(href, options), 3000),
330→      ] as [
331→        string,
332→        vocab.Object | null,
333→      ];
334→    } catch (_) {
335→      return null;
336→    }
337→  });
338→  for (const pair of await Promise.all(promises)) {
339→    if (pair == null) continue;
340→    const [href, object] = pair;
341→    if (!isActor(object)) continue;
342→    let actor = await persistActor(fedCtx, object, {
343→      ...options,
344→      outbox: false,
345→    });
346→    if (actor == null) continue;
347→    if (actor.iri !== href && !actor.aliases.includes(href)) {
348→      const aliases = [...actor.aliases, href];
349→      await db.update(actorTable)
350→        .set({ aliases })
351→        .where(eq(actorTable.id, actor.id));
352→      actor = { ...actor, aliases };
353→    }
354→    actors.push(actor);
355→  }
356→  if (options.kv != null && cacheKey != null) {
357→    await options.kv.set(cacheKey, actors);
358→  }
359→  return actors.map((actor) => ({ actor }));
360→}
