@Composable
fun HtmlContent(
    html: String,
    maxLines: Int = Int.MAX_VALUE,
    modifier: Modifier = Modifier,
    onMentionClick: ((handle: String) -> Unit)? = null,
    onLinkClick: ((url: String) -> Unit)? = null
