    val isDark = isSystemInDarkTheme()
    val linkColor = if (isDark) Color(0xFF60A5FA) else Color(0xFF2563EB)
    val mentionBg = linkColor.copy(alpha = 0.10f)
    val textColor = MaterialTheme.colorScheme.onSurface

