 229→        }),
 230→      },
 231→      select: (args) => ({
 232→        with: {
 233→          articleSource: {
 234→            with: {
 235→              contents: {
 236→                where: {
 237→                  beingTranslated: args.includeBeingTranslated ?? false,
 238→                },
 239→              },
 240→            },
 241→          },
 242→        },
 243→      }),
 244→      resolve(post, args) {
 245→        const contents = post.articleSource?.contents ?? [];
 246→        if (args.language == null) return contents;
 247→        const availableLocales = contents.map((c) => c.language);
