 501→builder.relayMutationField(
 502→  "createNote",
 503→  {
 504→    inputFields: (t) => ({
 505→      visibility: t.field({ type: PostVisibility, required: true }),
 506→      content: t.field({ type: "Markdown", required: true }),
 507→      language: t.field({ type: "Locale", required: true }),
 508→      // TODO: media
 509→      replyTargetId: t.globalID({
 510→        for: [Note, Article, Question],
 511→        required: false,
 512→      }),
 513→      quotedPostId: t.globalID({
 514→        for: [Note, Article, Question],
 515→        required: false,
 516→      }),
 517→    }),
 518→  },
 519→  {
 520→    errors: {
 521→      types: [
 522→        NotAuthenticatedError,
 523→        InvalidInputError,
 524→      ],
 525→    },
 526→    async resolve(_root, args, ctx) {
 527→      const session = await ctx.session;
 528→      if (session == null) {
 529→        throw new NotAuthenticatedError();
 530→      }
 531→      const { visibility, content, language, replyTargetId, quotedPostId } =
 532→        args.input;
 533→      let replyTarget: schema.Post & { actor: schema.Actor } | undefined;
 534→      if (replyTargetId != null) {
 535→        replyTarget = await ctx.db.query.postTable.findFirst({
 536→          with: { actor: true },
 537→          where: { id: replyTargetId.id },
 538→        });
 539→        if (replyTarget == null) {
 540→          throw new InvalidInputError("replyTargetId");
 541→        }
 542→      }
 543→      let quotedPost: schema.Post & { actor: schema.Actor } | undefined;
 544→      if (quotedPostId != null) {
 545→        quotedPost = await ctx.db.query.postTable.findFirst({
 546→          with: { actor: true },
 547→          where: { id: quotedPostId.id },
 548→        });
 549→        if (quotedPost == null) {
 550→          throw new InvalidInputError("quotedPostId");
 551→        }
 552→      }
 553→      return await withTransaction(ctx.fedCtx, async (context) => {
 554→        const note = await createNote(
 555→          context,
 556→          {
 557→            accountId: session.accountId,
 558→            visibility: visibility === "PUBLIC"
 559→              ? "public"
 560→              : visibility === "UNLISTED"
 561→              ? "unlisted"
 562→              : visibility === "FOLLOWERS"
 563→              ? "followers"
 564→              : visibility === "DIRECT"
 565→              ? "direct"
 566→              : visibility === "NONE"
 567→              ? "none"
 568→              : assertNever(
 569→                visibility,
 570→                `Unknown value in Post.visibility: "${visibility}"`,
 571→              ),
 572→            content,
 573→            language: language.baseName,
 574→            media: [], // TODO
 575→          },
 576→          { replyTarget, quotedPost },
 577→        );
 578→        if (note == null) {
 579→          throw new Error("Failed to create note");
 580→        }
 581→        return note;
 582→      });
 583→    },
 584→  },
 585→  {
 586→    outputFields: (t) => ({
 587→      note: t.field({
 588→        type: Note,
 589→        resolve(result) {
 590→          return result;
 591→        },
 592→      }),
 593→    }),
 594→  },
 595→);
