 981→          mentions: true,
 982→        },
 983→        where: { id: postId.id },
 984→      });
 985→
 986→      if (post == null) {
 987→        throw new InvalidInputError("postId");
 988→      }
 989→
 990→      if (!isPostVisibleTo(post, ctx.account.actor)) {
 991→        throw new InvalidInputError("postId");
 992→      }
 993→
 994→      const share = await sharePost(
 995→        ctx.fedCtx,
 996→        ctx.account,
 997→        post,
 998→      );
 999→
1000→      return {
1001→        share,
1002→        originalPostId: postId.id,
1003→      };
1004→    },
1005→  },
1006→  {
1007→    outputFields: (t) => ({
1008→      share: t.field({
1009→        type: Post,
1010→        resolve(result) {
1011→          return result.share;
1012→        },
1013→      }),
1014→      originalPost: t.drizzleField({
1015→        type: Post,
1016→        async resolve(query, result, _args, ctx) {
1017→          const post = await ctx.db.query.postTable.findFirst(
1018→            query({ where: { id: result.originalPostId } }),
1019→          );
1020→          return post!;
1021→        },
1022→      }),
1023→    }),
1024→  },
1025→);
1026→
1027→builder.relayMutationField(
1028→  "unsharePost",
1029→  {
1030→    inputFields: (t) => ({
1031→      postId: t.globalID({
1032→        for: [Note, Article, Question],
1033→        required: true,
1034→      }),
1035→    }),
1036→  },
1037→  {
1038→    errors: {
1039→      types: [
1040→        NotAuthenticatedError,
1041→        InvalidInputError,
1042→      ],
1043→    },
1044→    async resolve(_root, args, ctx) {
1045→      if (ctx.account == null) {
1046→        throw new NotAuthenticatedError();
1047→      }
1048→
1049→      const { postId } = args.input;
1050→
1051→      const post = await ctx.db.query.postTable.findFirst({
1052→        with: {
1053→          actor: {
1054→            with: {
1055→              followers: true,
1056→              blockees: true,
1057→              blockers: true,
1058→            },
1059→          },
1060→          replyTarget: {
1061→            with: { actor: true },
1062→          },
1063→          mentions: true,
1064→        },
1065→        where: { id: postId.id },
1066→      });
1067→
1068→      if (post == null) {
1069→        throw new InvalidInputError("postId");
1070→      }
1071→
1072→      if (!isPostVisibleTo(post, ctx.account.actor)) {
1073→        throw new InvalidInputError("postId");
1074→      }
1075→
1076→      const unshared = await unsharePost(
1077→        ctx.fedCtx,
1078→        ctx.account,
1079→        post,
1080→      );
1081→
1082→      if (unshared == null) {
1083→        throw new InvalidInputError("postId");
1084→      }
1085→
1086→      return { success: true, originalPostId: postId.id };
1087→    },
1088→  },
1089→  {
1090→    outputFields: (t) => ({
1091→      originalPost: t.drizzleField({
1092→        type: Post,
1093→        async resolve(query, result, _args, ctx) {
1094→          const post = await ctx.db.query.postTable.findFirst(
1095→            query({ where: { id: result.originalPostId } }),
1096→          );
1097→          return post!;
1098→        },
1099→      }),
1100→    }),
1101→  },
1102→);
1103→
1104→builder.queryField("articleDraft", (t) =>
1105→  t.field({
1106→    type: ArticleDraft,
1107→    nullable: true,
1108→    args: {
1109→      id: t.arg.globalID({ for: [ArticleDraft], required: false }),
1110→      uuid: t.arg({ type: "UUID", required: false }),
1111→    },
1112→    async resolve(_root, args, ctx) {
1113→      if (ctx.account == null) return null;
1114→
1115→      // At least one of id or uuid must be provided
1116→      if (!args.id && !args.uuid) {
1117→        throw new Error("Either id or uuid must be provided");
1118→      }
1119→
1120→      // Use uuid if provided, otherwise use id
1121→      const draftId = args.uuid ?? args.id!.id;
1122→
1123→      const drafts = await ctx.db
1124→        .select()
1125→        .from(articleDraftTable)
1126→        .where(
1127→          and(
1128→            eq(articleDraftTable.id, draftId),
1129→            eq(articleDraftTable.accountId, ctx.account.id),
1130→          ),
1131→        )
1132→        .limit(1);
1133→
1134→      return drafts[0] ?? null;
1135→    },
1136→  }));
