export interface NoteCardInternalProps {
  $note: NoteCardInternal_note$key;
}

export function NoteCardInternal(props: NoteCardInternalProps) {
  const note = createFragment(
    graphql`
      fragment NoteCardInternal_note on Note {
        __id
        uuid
        content
        language
        actor {
          ...PostAvatar_actor
        }
        ...PostControls_note
        ...NoteMedia_note
        ...LinkPreview_note
