  1→package pub.hackers.android.ui.components
  2→
  3→import androidx.compose.foundation.isSystemInDarkTheme
  4→import androidx.compose.foundation.text.ClickableText
  5→import androidx.compose.material3.MaterialTheme
  6→import androidx.compose.runtime.Composable
  7→import androidx.compose.runtime.remember
  8→import androidx.compose.ui.Modifier
  9→import androidx.compose.ui.graphics.Color
 10→import androidx.compose.ui.platform.LocalUriHandler
 11→import androidx.compose.ui.text.AnnotatedString
 12→import androidx.compose.ui.text.SpanStyle
 13→import androidx.compose.ui.text.buildAnnotatedString
 14→import androidx.compose.ui.text.font.FontWeight
 15→import androidx.compose.ui.text.style.TextDecoration
 16→import androidx.compose.ui.text.style.TextOverflow
 17→import androidx.compose.ui.text.withStyle
 18→import java.net.URI
 19→
 20→private enum class LinkType {
 21→    MENTION, HASHTAG, REGULAR
 22→}
 23→
 24→private val TAG_REGEX = Regex("""<(/?)(\w+)([^>]*)>""")
 25→private val ATTR_REGEX = Regex("""([\w-]+)=["']([^"']*)["']""")
 26→
 27→@Composable
 28→fun HtmlContent(
 29→    html: String,
 30→    maxLines: Int = Int.MAX_VALUE,
 31→    modifier: Modifier = Modifier,
 32→    onMentionClick: ((handle: String) -> Unit)? = null,
 33→    onLinkClick: ((url: String) -> Unit)? = null
 34→) {
 35→    val uriHandler = LocalUriHandler.current
 36→    val isDark = isSystemInDarkTheme()
 37→    val linkColor = if (isDark) Color(0xFF60A5FA) else Color(0xFF2563EB)
 38→    val mentionBg = linkColor.copy(alpha = 0.10f)
 39→    val textColor = MaterialTheme.colorScheme.onSurface
 40→
 41→    val annotatedString = remember(html, linkColor, mentionBg) {
 42→        parseHtmlToAnnotatedString(html, linkColor, mentionBg)
 43→    }
 44→
 45→    ClickableText(
 46→        text = annotatedString,
 47→        style = MaterialTheme.typography.bodyMedium.copy(color = textColor),
 48→        maxLines = maxLines,
 49→        overflow = TextOverflow.Ellipsis,
 50→        modifier = modifier,
 51→        onClick = { offset ->
 52→            // Check mentions first
 53→            annotatedString.getStringAnnotations("MENTION", offset, offset)
 54→                .firstOrNull()?.let { annotation ->
 55→                    val handle = extractHandleFromUrl(annotation.item)
 56→                    if (handle != null && onMentionClick != null) {
 57→                        onMentionClick(handle)
 58→                    } else {
 59→                        try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
 60→                    }
 61→                    return@ClickableText
 62→                }
 63→
 64→            // Then regular links and hashtags
 65→            annotatedString.getStringAnnotations("URL", offset, offset)
 66→                .firstOrNull()?.let { annotation ->
 67→                    if (onLinkClick != null) {
 68→                        onLinkClick(annotation.item)
 69→                    } else {
 70→                        try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
 71→                    }
 72→                }
 73→        }
 74→    )
 75→}
 76→
 77→/**
 78→ * Extracts a fediverse handle from a mention URL.
 79→ * e.g. "https://hackers.pub/@user" -> "user@hackers.pub"
 80→ *      "https://mastodon.social/@user" -> "user@mastodon.social"
 81→ */
 82→private fun extractHandleFromUrl(url: String): String? {
 83→    return try {
 84→        val uri = URI(url)
 85→        val host = uri.host ?: return null
 86→        val path = uri.path ?: return null
 87→        val username = path.trimStart('/').removePrefix("@")
 88→        if (username.isNotEmpty()) "$username@$host" else null
 89→    } catch (_: Exception) {
 90→        null
 91→    }
 92→}
 93→
 94→private fun parseHtmlToAnnotatedString(
 95→    html: String,
 96→    linkColor: Color,
 97→    mentionBg: Color
 98→): AnnotatedString {
 99→    return buildAnnotatedString {
100→        var currentLinkType: LinkType? = null
101→        var hasAnnotation = false
102→        var insideInvisibleSpan = false
103→        var invisibleSpanDepth = 0
104→        var hasContent = false
105→
106→        var pos = 0
107→        val source = html.trim()
108→
109→        while (pos < source.length) {
110→            val tagMatch = TAG_REGEX.find(source, pos)
111→
112→            // Handle text before the next tag (or remaining text if no more tags)
113→            if (tagMatch == null || tagMatch.range.first > pos) {
114→                val textEnd = tagMatch?.range?.first ?: source.length
115→                val rawText = source.substring(pos, textEnd)
116→                val decoded = decodeHtmlEntities(rawText)
117→
118→                if (!insideInvisibleSpan && decoded.isNotEmpty()) {
119→                    val isInterBlockWhitespace = decoded.isBlank() && decoded.contains('\n')
120→                    if (!isInterBlockWhitespace) {
121→                        appendStyledText(this, decoded, currentLinkType, linkColor, mentionBg)
122→                        hasContent = true
123→                    }
124→                }
125→
126→                pos = textEnd
127→            }
128→
129→            if (tagMatch != null && tagMatch.range.first == pos) {
130→                val isClosing = tagMatch.groupValues[1] == "/"
131→                val tagName = tagMatch.groupValues[2].lowercase()
132→                val attrString = tagMatch.groupValues[3]
133→
134→                if (!isClosing) {
135→                    val attrs = parseAttributes(attrString)
136→
137→                    when (tagName) {
138→                        "p" -> {
139→                            if (hasContent) append("\n\n")
140→                        }
141→                        "br" -> {
142→                            append("\n")
143→                        }
144→                        "a" -> {
145→                            val classes = attrs["class"] ?: ""
146→                            val href = attrs["href"] ?: ""
147→
148→                            currentLinkType = when {
149→                                "hashtag" in classes -> LinkType.HASHTAG
150→                                "mention" in classes -> LinkType.MENTION
151→                                href.isNotEmpty() -> LinkType.REGULAR
152→                                else -> null
153→                            }
154→
155→                            if (href.isNotEmpty()) {
156→                                val tag = if (currentLinkType == LinkType.MENTION) "MENTION" else "URL"
157→                                pushStringAnnotation(tag, href)
158→                                hasAnnotation = true
159→                            }
160→                        }
161→                        "span" -> {
162→                            val classes = attrs["class"] ?: ""
163→                            if ("invisible" in classes) {
164→                                insideInvisibleSpan = true
165→                                invisibleSpanDepth++
166→                            }
167→                        }
168→                    }
169→                } else {
170→                    when (tagName) {
171→                        "a" -> {
172→                            if (hasAnnotation) {
173→                                pop()
174→                                hasAnnotation = false
175→                            }
176→                            currentLinkType = null
177→                        }
178→                        "span" -> {
179→                            if (insideInvisibleSpan) {
180→                                invisibleSpanDepth--
181→                                if (invisibleSpanDepth <= 0) {
182→                                    insideInvisibleSpan = false
183→                                    invisibleSpanDepth = 0
184→                                }
185→                            }
186→                        }
187→                    }
188→                }
189→
190→                pos = tagMatch.range.last + 1
191→            }
192→        }
193→    }
194→}
195→
196→private fun appendStyledText(
197→    builder: AnnotatedString.Builder,
198→    text: String,
199→    linkType: LinkType?,
200→    linkColor: Color,
201→    mentionBg: Color
202→) {
203→    when (linkType) {
204→        LinkType.MENTION -> {
205→            builder.withStyle(
206→                SpanStyle(
207→                    color = linkColor,
208→                    fontWeight = FontWeight.SemiBold,
209→                    background = mentionBg
210→                )
211→            ) {
212→                append(text)
213→            }
214→        }
215→        LinkType.HASHTAG -> {
216→            builder.withStyle(SpanStyle(color = linkColor)) {
217→                append(text)
218→            }
219→        }
220→        LinkType.REGULAR -> {
221→            builder.withStyle(
222→                SpanStyle(
223→                    color = linkColor,
224→                    textDecoration = TextDecoration.Underline
225→                )
226→            ) {
227→                append(text)
228→            }
229→        }
230→        null -> {
231→            builder.append(text)
232→        }
233→    }
234→}
235→
236→private fun parseAttributes(attrString: String): Map<String, String> {
237→    val attrs = mutableMapOf<String, String>()
238→    for (match in ATTR_REGEX.findAll(attrString)) {
239→        attrs[match.groupValues[1]] = match.groupValues[2]
240→    }
241→    return attrs
242→}
243→
244→private fun decodeHtmlEntities(text: String): String {
245→    return text
